    SessionCache *cache = create_session_cache();
    if (!cache) {
        printf("Failed to create session cache\n");
        return 1;
    }
    
    create_session(cache, "session_001", "user_data_for_alice");
    create_session(cache, "session_002", "user_data_for_bob");
